// Some portions generated by Codex

package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.ByteBuffer;
import java.nio.ByteOrder;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class OmniWitnessPersistenceStoreTest {

	private static final long SEED = 0x51E7C0DEL;
	private static final int VALUE_RECORD_FIXED_BYTES = Long.BYTES + Long.BYTES + Integer.BYTES + Float.BYTES
			+ Double.BYTES;

	@Test
	void valueRecordsStoreSamplingProbabilityAndMinimumDetectableEstimate(@TempDir Path tempDir) throws Exception {
		OmniJoinEstimator estimator = new OmniJoinEstimator(64, 4, 64, SEED);
		OmniJoinEstimator.Relation events = estimator.relation(OmniRelation.STATEMENT);
		long code = OmniJoinEstimator.stableHash("A");
		events.updateStatic(OmniAttributeRef.component(1), code, OmniJoinEstimator.stableHash("event:1"), 1.0d);

		try (OmniWitnessPersistenceStore store = OmniWitnessPersistenceStore.open(tempDir)) {
			store.writeSnapshot((byte) 0, estimator, 1L);
		}

		ByteBuffer data = ByteBuffer.wrap(Files.readAllBytes(tempDir.resolve("join-estimator/omni-witness-a.dat")))
				.order(ByteOrder.BIG_ENDIAN);
		int valueRecordOffset = data.getInt(Integer.BYTES * 6);
		int postingOffset = data.getInt(Integer.BYTES * 7);

		assertEquals(VALUE_RECORD_FIXED_BYTES, postingOffset - valueRecordOffset,
				"Value records need room for sampling probability and min-detectable estimate");
		float samplingProbability = data.getFloat(valueRecordOffset + Long.BYTES + Long.BYTES + Integer.BYTES);
		double minDetectableEstimate = data
				.getDouble(valueRecordOffset + Long.BYTES + Long.BYTES + Integer.BYTES + Float.BYTES);
		assertTrue(samplingProbability > 0.0f && samplingProbability <= 1.0f);
		assertTrue(minDetectableEstimate >= 0.0d);
	}

	@Test
	void witnessPersistenceUsesDedicatedIndexAndSnapshotWriterAbstractions() {
		String packageName = OmniWitnessPersistenceStore.class.getPackageName();

		assertDoesNotThrow(() -> Class.forName(packageName + ".MappedWitnessIndex"));
		assertDoesNotThrow(() -> Class.forName(packageName + ".OverlayWitnessIndex"));
		assertDoesNotThrow(() -> Class.forName(packageName + ".CompositeWitnessIndex"));
		assertDoesNotThrow(() -> Class.forName(packageName + ".OmniWitnessSnapshotWriter"));
	}
}
